	import sailpoint.object.Filter;
	import sailpoint.object.QueryOptions;
	import sailpoint.object.IdentityRequest;
	import java.lang.StringBuilder;
	import sailpoint.tools.Util;
	import java.util.Date;
	import java.text.SimpleDateFormat; 
	import sailpoint.tools.Message;
	import java.util.Calendar;
	import sailpoint.api.SailPointContext;
	import sailpoint.api.SailPointFactory;
	import sailpoint.object.Identity;
	import sailpoint.object.EmailOptions;
	import sailpoint.object.EmailTemplate;
	import sailpoint.object.EmailFileAttachment;
	
	int createdWithInDays = 30;

	if(config!=null){
		createdWithInDays = Integer.parseInt(config.get("createdWithInDays"));
	}

  QueryOptions ops = new QueryOptions();

  ops.addFilter(Filter.eq("type","AccessRequest"));

  List identityRequests = context.getObjects(IdentityRequest.class, ops);
  
  //List idReqs = new ArrayList();
  StringBuilder outputString = new StringBuilder();
  
  SimpleDateFormat createDateSFD = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss");
  
	Calendar cal = Calendar.getInstance();
	cal.add(Calendar.DATE, -createdWithInDays); //getting the date 30 days before current date
	Date createAfterDate = cal.getTime();
	Date currentDate = new Date();
  //Date createAfterDate = createDateSFD.parse("09/29/2021"); 
  
  // outputString.append("IdentityRequests with errors After Date: " + createAfterDate).append("\n\n");
  
  errorMsgEndWith = "java.net.SocketException: Connection reset";
  Boolean containErrorMsg = false;
 
  outputString.append("IdentityRequestName,Requestee samAccountName,Requestee IdentityCubeName,Requestee Name,Requester SamAccountName,Requester IdentityCubeName,Requester Name,Created Date, Days Since Created, ServiceNow Short Description, Assigned To, Replacement Ticket").append("\n");
  if (idenityRequests !=null) {
    for (IdentityRequest identityRequest : identityRequests) {
      //idReqs.add(identityRequest.getName());
		if(identityRequest != null) {
			//check if it is created is within last 30 days
			if (identityRequest.getCreated().after(createAfterDate) && identityRequest.getErrors() != null) {
				
				List errors = identityRequest.getErrors();
				containErrorMsg = false;
				for (Message errMsg : errors) {
					if (errMsg.getMessage().contains(errorMsgEndWith)) {
						
						containErrorMsg = true;
						break;
					}
				}
				if (containErrorMsg) {	
				
					if ((context == void) || (context == null)) {
						context = SailPointFactory.getCurrentContext();
					}
					
					requesteeName = context.getObjectById(Identity.class, identityRequest.getTargetId()).getName();
					requesteeSamAccountName = context.getObjectById(Identity.class, identityRequest.getTargetId()).getAttribute("samAccountName");
					
					requesterName = context.getObjectById(Identity.class, identityRequest.getRequesterId()).getName();
					requesterSamAccountName = context.getObjectById(Identity.class, identityRequest.getRequesterId()).getAttribute("samAccountName");
					
					serviceNowDescription = "IdentityIQ Access Request " + identityRequest.getName();
					
					long diff = (currentDate.getTime() - identityRequest.getCreated().getTime())/(24 * 60 * 60 * 1000); 
				
					outputString.append(identityRequest.getName()).append(",").append(requesteeSamAccountName).append(",").append(requesteeName).append(",").append('"').append(identityRequest.getTargetDisplayName()).append('"').append(",").append(requesterSamAccountName).append(",").append(requesterName).append(",").append('"').append(identityRequest.getRequesterDisplayName()).append('"').append(",").append(createDateSFD.format(identityRequest.getCreated())).append(",").append(diff).append(",").append(serviceNowDescription).append("\n");
				}		
			}
		}
        
    }
      
 }
 
 
//setting up email report
Map emailArgs = new HashMap();
List emailTo = new ArrayList();
emailTo.add("michael.mann@ascension.org");
emailTo.add("brian.martin@ascension.org");
//emailTo.add("anurag.nayak@ascension-external.org");

String subject = "Report of Access Requests With Connection reset Errors" + " :Report Date: " + currentDate;

StringBuilder sb = new StringBuilder();
sb.append("Report Generation Date: ").append(currentDate).append("\n");
sb.append("Access Requests with Connection reset Errors created after: ").append(createAfterDate).append("\n\n");

emailArgs.put("subject", subject);
emailArgs.put("report", sb.toString());

EmailOptions emailOps = new EmailOptions(emailTo, emailArgs);
EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-ReportOfExpiringADAccts");
fileName = "Report-Access Requests With Connection Reset Errors-" + createDateSFD.format(currentDate)+".csv";
EmailFileAttachment fileAttachement = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_CSV, outputString.toString().getBytes());
emailOps.addAttachment(fileAttachement);

context.sendEmailNotification(emailTemplate, emailOps);

return "Success";
